import pygame
import base64
import io
pygame.init()
WIDTH, HEIGHT = 800, 400
screen = pygame.display.set_mode((WIDTH, HEIGHT))
pygame.display.set_caption("T-Rex Runner with Embedded Image")
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
clock = pygame.time.Clock()
FPS = 60
dino_width, dino_height = 40, 60
dino_x, dino_y = 50, HEIGHT - dino_height - 40
dino_vel_y = 0
gravity = 1
jump_strength = 15
is_jumping = False
cactus_width, cactus_height = 20, 50
cactus_list = []
cactus_speed = 8
SPAWN_EVENT = pygame.USEREVENT + 1
pygame.time.set_timer(SPAWN_EVENT, 1500)
font = pygame.font.SysFont(None, 36)
score = 0
# Paste your Base64 string here between the triple quotes
dino_base64 = """

"""
# Decode Base64 and load image
dino_bytes = base64.b64decode(dino_base64)
dino_image_file = io.BytesIO(dino_bytes)
dino_img = pygame.image.load(dino_image_file)
dino_img = pygame.transform.scale(dino_img, (dino_width, dino_height))
def draw_dino(x, y):
    screen.blit(dino_img, (x, y))
def draw_cactus(cactus_list):
    for cactus in cactus_list:
        pygame.draw.rect(screen, BLACK, cactus)
def check_collision(dino_rect, cactus_list):
    for cactus in cactus_list:
        if dino_rect.colliderect(cactus):
            return True
    return False
running = True
while running:
    clock.tick(FPS)
    screen.fill(WHITE)
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            running = False
        if event.type == SPAWN_EVENT:
            cactus_x = WIDTH
            cactus_y = HEIGHT - cactus_height - 40
            cactus_list.append(pygame.Rect(cactus_x, cactus_y, cactus_width, cactus_height))
    keys = pygame.key.get_pressed()
    if not is_jumping:
        if keys[pygame.K_SPACE]:
            dino_vel_y = -jump_strength
            is_jumping = True
    dino_vel_y += gravity
    dino_y += dino_vel_y
    if dino_y >= HEIGHT - dino_height - 40:
        dino_y = HEIGHT - dino_height - 40
        is_jumping = False
    for cactus in cactus_list:
        cactus.x -= cactus_speed
    cactus_list = [c for c in cactus_list if c.x + cactus_width > 0]
    draw_dino(dino_x, dino_y)
    draw_cactus(cactus_list)
    dino_rect = pygame.Rect(dino_x, dino_y, dino_width, dino_height)
    if check_collision(dino_rect, cactus_list):
        running = False
    score += 1
    score_text = font.render(f"Score: {score // 10}", True, BLACK)
    screen.blit(score_text, (10, 10))
    pygame.display.flip()
screen.fill(WHITE)
game_over_text = font.render("Game Over! Press any key to quit.", True, BLACK)
screen.blit(game_over_text, (WIDTH // 2 - game_over_text.get_width() // 2, HEIGHT // 2))
pygame.display.flip()
waiting = True
while waiting:
    for event in pygame.event.get():
        if event.type == pygame.KEYDOWN or event.type == pygame.QUIT:
            waiting = False
pygame.quit()






















































